"use client";

import { useEffect, useState } from "react";
import Echo from "laravel-echo";
import Pusher from "pusher-js";

interface PriceData {
  symbol: string;
  price: number;
  timestamp: number;
}

let echo: Echo<"reverb"> | null = null;

function getEcho(): Echo<"reverb"> {
  if (!echo) {
    (window as any).Pusher = Pusher;

    echo = new Echo({
      broadcaster: "reverb",
      key: process.env.NEXT_PUBLIC_REVERB_APP_KEY!,
      wsHost: process.env.NEXT_PUBLIC_REVERB_HOST ?? "localhost",
      wsPort: Number(process.env.NEXT_PUBLIC_REVERB_PORT ?? 8080),
      wssPort: Number(process.env.NEXT_PUBLIC_REVERB_PORT ?? 8080),
      forceTLS: (process.env.NEXT_PUBLIC_REVERB_SCHEME ?? "http") === "https",
      enabledTransports: ["ws", "wss"],
    });
  }
  return echo;
}

export function useBinancePrice(symbol = "BTCUSDT") {
  const [price, setPrice] = useState<number | null>(null);
  const [timestamp, setTimestamp] = useState<number | null>(null);
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    const echoInstance = getEcho();

    echoInstance.connector.pusher.connection.bind("connected", () =>
      setConnected(true),
    );
    echoInstance.connector.pusher.connection.bind("disconnected", () =>
      setConnected(false),
    );

    const channel = echoInstance
      .channel("binance.prices")
      .listen(".price.updated", (data: PriceData) => {
        if (data.symbol === symbol) {
          setPrice(data.price);
          setTimestamp(data.timestamp);
        }
      });

    return () => {
      channel.stopListening(".price.updated");
    };
  }, [symbol]);

  return { price, timestamp, connected };
}
